INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cf446b4c-moex-00314', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-2909f946', 'sub-judicial-cf446b4c-03', NULL, 'essay', '被告甲因涉嫌吸食毒品、竊盜、持有槍枝、詐欺等行為遭起訴，第一審
法院審理後判決：甲吸食第一級毒品、竊盜之行為乃分別起意之行為，
均有罪，其餘部分均無罪。經被告上訴後，第二審法院亦認為甲僅就吸
食毒品、竊盜之行為有罪，惟第二審法院僅在判決主文記載甲吸食毒品
部分有罪，對於竊盜部分，主文並未記載，但於判決之事實及理由欄中
有論及法院認定甲竊盜有罪之事實與理由。試問：甲若欲對於法院判決
請求救濟，應如何為之？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "de8fc5c719ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00315', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'essay', '甲乙兩人結褵數載，鶼鰈情深。乙平日在家操持家務，甲趁著數日連假，
開著愛車載乙遊歷花東。不料途中遭酒駕的丙衝撞（酒精濃度超過每公
升零點一五毫克），甲不僅愛車全毀，且全身骨折、五臟六腑俱受重創，
乙則奇蹟似地毫髮無傷。甲於住院治療期間，頻繁接受手術，加上頓時
失去收入及須支付龐大醫療費用等壓力，痛苦萬分，所幸尚有乙日夜相
伴照料。惟甲在治療數月之後，仍傷重不治死亡。乙悲痛地為甲辦理後
事。乙係甲唯一的繼承人。試問：乙對丙有何權利可資主張？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00316', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'essay', '甲與乙、丙共有A地，三人應有部分登記各三分之一。某日，甲乙不顧
丙之反對將 A地以低於市場行情的租金出租且交付於丁使用。試問：
丙得否請求丁將 A地返還於全體共有人？若不得，丙有何其他救濟手
段可資主張？（10 分）
若丙無奈之餘，向好友戊傾訴此事，經戊慫恿，丙將其應有部分讓與
戊。試問：戊得否請求丁將 A地返還於全體共有人？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00317', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '財團法人之董事，代表法人向他人借款，嗣後何人應就此一借款債務，負清償責任？', '["法人單獨負責", "董事單獨負責", "法人、董事個別負責", "法人、董事均不須負責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00318', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於甲主張其與乙通謀而為之虛偽意思表示無效，及丁之債權人丙依民法第244條向法院聲請撤 銷丁對戊無償贈與其金錢之行為之情形，下列敘述，何者正確？', '["甲、丁之意思表示均為有效意思表示", "甲僅得於與乙所為者係有償行為之情形，始得主張無效", "甲乙間之法律行為不限於財產行為，丁戊間之法律行為則限於財產行為", "即使丁對戊之贈與未害及丙對丁之債權，丙仍得聲請法院撤銷該贈與行為 20420 20520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00319', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲現年 17 歲，假造其父母之同意函，向經營機車行之乙購買機車 1 輛。甲乙間買賣契約之效力 如何？', '["有效但得撤銷", "效力未定", "無效", "有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00320', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '依民法規定，關於旅客之行李，下列敘述，何者錯誤？', '["運送人對於旅客所交託之行李，如未另收運費，不適用物品運送之規定", "運送人對於旅客所未交託之行李，如因自己之過失致有毀損者，仍負責任", "運送人對於旅客所未交託之行李，如因其受僱人之過失致有毀損者，仍負責任", "運送人對於旅客所未交託之行李，如因其他旅客之過失致有喪失者，不負責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00321', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲登記為A屋所有人。關於甲如何行使A屋所有權，下列敘述，何者錯誤？', '["甲得將A屋所有權讓與他人", "甲得請求無權占有A屋之人返還A屋", "甲得使用收益A屋", "甲得於A屋上設定普通地上權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00322', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於不動產役權之敘述，何者錯誤？', '["不動產役權係以他人不動產供特定便宜之用為目的", "不動產役權係需役不動產之從權利", "不動產役權因時效而取得者，以繼續並表見者為限", "不動產役權不得就自己之不動產設定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00323', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-111-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲女未婚生下乙女，在乙5歲時，將乙出養於丙、丁夫妻，並與丙之母親戊共同生活。10年後， 某日丙、丁不幸遭遇空難，同時死亡。乙為賺取學費，欲在己經營之速食店打工，其僱傭契約應 經下列何者允許？', '["無庸得任何人之允許", "甲", "乙之生父", "戊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:23+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "204", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
